import logo from './logo.png';
import './App.css';

function Description() {
  return (
    <div className="Description">
      <p>
        Goosecollab is a platform for UWaterloo Engineering students that
        allows engineers to find other engineers for their capstone projects.
      </p>
      <p>
        Made for EngHacks 2026, by Arulini, Franklin, Girish, and Jeff!
      </p>
    </div>
  )
}

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo"/>
        <h1>
          Goosecollab
        </h1>
        <Description />
      </header>
    </div>
  );
}

export default App;
